using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;
using System.IO;
using System.Linq;

namespace YourNamespace.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FileController : ControllerBase
    {
        private readonly string _uploadsFolder;
        private readonly IContentTypeProvider _contentTypeProvider;
        private readonly string[] _allowedExtensions = new[]
        {
            ".pdf", ".doc", ".docx", ".xls", ".xlsx", ".ppt", ".pptx",
            ".txt", ".csv", ".jpg", ".jpeg", ".png", ".gif", ".bmp",
            ".svg", ".webp", ".zip", ".rar"
        };

        public FileController(IWebHostEnvironment environment, IContentTypeProvider contentTypeProvider)
        {
            _uploadsFolder = Path.Combine(environment.ContentRootPath, "uploads");
            _contentTypeProvider = contentTypeProvider;
        }

        [HttpGet("{filename}")]
        public IActionResult GetFile(string filename)
        {
            if (string.IsNullOrWhiteSpace(filename))
            {
                return BadRequest("Filename is required");
            }

            filename = Path.GetFileName(filename);

            if (filename != Path.GetFileName(filename) || filename.Contains(".."))
            {
                return BadRequest("Invalid filename");
            }

            var extension = Path.GetExtension(filename).ToLowerInvariant();
            if (!_allowedExtensions.Contains(extension))
            {
                return BadRequest("File type not allowed");
            }

            var filePath = Path.Combine(_uploadsFolder, filename);

            var fullPath = Path.GetFullPath(filePath);
            var uploadsFullPath = Path.GetFullPath(_uploadsFolder);

            if (!fullPath.StartsWith(uploadsFullPath + Path.DirectorySeparatorChar) &&
                !fullPath.Equals(uploadsFullPath))
            {
                return BadRequest("Invalid file path");
            }

            if (!System.IO.File.Exists(filePath))
            {
                return NotFound("File not found");
            }

            if (!_contentTypeProvider.TryGetContentType(filename, out var contentType))
            {
                contentType = "application/octet-stream";
            }

            var fileStream = new FileStream(filePath, FileMode.Open, FileAccess.Read, FileShare.Read);
            return File(fileStream, contentType, filename);
        }
    }
}